// ============================================================
// NODE: Clean + Enrich
// - Strips '(Deactivated User)' from rep names
// - Derives Year, Quarter, YearQuarter from Close Date
// - Normalises CRM platform variants
// - Fills nulls with sensible defaults
// - Excludes any residual NURTURE_EXCLUDE rows
// - Service Line removed (no longer tracked at Full Funnel)
// ============================================================

const rows = $input.all().map(item => item.json);
const cleaned = [];

for (const row of rows) {
  const outcome = (row['Deal Outcome'] || '').trim().toUpperCase();

  // Safety net: exclude nurture if any slipped through
  if (outcome === 'NURTURE_EXCLUDE' || !outcome) continue;

  // ---- Rep name: strip deactivated suffix --------------------
  const rawOwner = (row['Deal owner'] || 'Unknown').trim();
  const dealOwner = rawOwner.replace(/\s*\(Deactivated User\)/gi, '').trim() || 'Unknown';

  // ---- Dates & time derivations ------------------------------
  const closeDateRaw  = (row['Close Date']  || '').trim();
  const createDateRaw = (row['Create Date'] || '').trim();

  let year        = 'Unknown';
  let quarter     = 'Unknown';
  let yearQuarter = 'Unknown';

  if (closeDateRaw) {
    const d = new Date(closeDateRaw);
    if (!isNaN(d)) {
      year = d.getFullYear().toString();
      const m = d.getMonth();
      if      (m <= 2) quarter = 'Q1';
      else if (m <= 5) quarter = 'Q2';
      else if (m <= 8) quarter = 'Q3';
      else             quarter = 'Q4';
      yearQuarter = year + '-' + quarter;
    }
  }

  // ---- CRM platform normalisation ----------------------------
  const crmRaw   = (row['Crm Platform'] || '').trim();
  const crmLower = crmRaw.toLowerCase();
  let crmNorm;
  if      (!crmRaw)                                       crmNorm = 'Unknown';
  else if (crmLower.indexOf('salesforce') !== -1)         crmNorm = 'Salesforce';
  else if (crmLower.indexOf('hubspot') !== -1)            crmNorm = 'HubSpot';
  else if (crmLower.indexOf('microsoft dynamics') !== -1) crmNorm = 'Microsoft Dynamics';
  else if (crmLower.indexOf('zoho') !== -1)               crmNorm = 'Zoho';
  else if (crmLower.indexOf('pipedrive') !== -1)          crmNorm = 'Pipedrive';
  else                                                    crmNorm = 'Other';

  const amount         = parseFloat(row['Amount']) || 0;
  const salesCycleDays = parseFloat(row['Sales_Cycle_Days']);
  const salesCycle     = (!isNaN(salesCycleDays) && salesCycleDays > 0) ? salesCycleDays : null;

  const revopsRaw = (row['Has Revops Function'] || '').toString().trim().toLowerCase();
  let hasRevops;
  if      (revopsRaw === 'true')  hasRevops = 'Has RevOps';
  else if (revopsRaw === 'false') hasRevops = 'No RevOps';
  else                            hasRevops = 'Unknown';

  cleaned.push({
    dealName:        (row['Deal Name'] || '').trim(),
    companyName:     (row['All Company Name'] || row['Associated Company'] || '').trim(),
    outcome:         outcome,
    isWon:           outcome === 'CLOSED_WON',
    amount:          amount,
    dealOwner:       dealOwner,
    closeDate:       closeDateRaw,
    createDate:      createDateRaw,
    year:            year,
    quarter:         quarter,
    yearQuarter:     yearQuarter,
    revenueTier:     (row['Revenue_Tier']          || 'Unknown').trim(),
    companySizeTier: (row['Company_Size_Tier']     || 'Unknown').trim(),
    industryTier:    (row['Industry_Tier']         || 'Unknown').trim(),
    companyType:     (row['Type with Fallback']    || 'Unknown').trim(),
    country:         (row['Country with Fallback'] || 'Unknown').trim().toUpperCase(),
    state:           (row['State']                 || '').trim(),
    crmPlatform:     crmNorm,
    hasRevops:       hasRevops,
    lostReason:      (row['Normalized_Lost_Reason'] || 'Not Provided').trim(),
    salesCycleDays:  salesCycle,
    marketingAuto:   (row['Marketing Automation']  || '').trim(),
    salesEngagement: (row['Sales Engagement']      || '').trim()
  });
}

return [{ json: { deals: cleaned, totalRows: cleaned.length } }];

// ============================================================
// NODE: Sanity Check
// Validates expected counts before running expensive AI call.
// Stops the workflow and surfaces a clear error if counts
// are off — saves wasted Anthropic API credits.
// ============================================================

const { deals } = $input.first().json;

const totalWon  = deals.filter(d => d.isWon).length;
const totalLost = deals.filter(d => !d.isWon).length;
const total     = deals.length;

const errors = [];

if (totalWon < 500 || totalWon > 550) {
  errors.push(`Won deals: ${totalWon} (expected ~525)`);
}
if (totalLost < 880 || totalLost > 950) {
  errors.push(`Lost deals: ${totalLost} (expected ~916)`);
}
if (total < 1400 || total > 1500) {
  errors.push(`Total deals: ${total} (expected 1,441)`);
}

if (errors.length > 0) {
  throw new Error(
    'SANITY CHECK FAILED — Do not proceed.\n\n' +
    errors.join('\n') +
    '\n\nLikely causes:\n' +
    '1. Deal Outcome values do not match CLOSED_WON / CLOSED_LOST (check caps/spacing)\n' +
    '2. Google Sheet tab name is wrong or sheet is empty\n' +
    '3. Rows were filtered unexpectedly in the Clean + Enrich node'
  );
}

// Pass through unchanged
return $input.all();

// ============================================================
// NODE: JS Pre-Calculate
// Computes every CvR table the AI Agent will reference.
// Service Line removed — no longer tracked at Full Funnel.
// RULE: AI Agent must NEVER calculate numbers itself.
// ============================================================

const { deals } = $input.first().json;

// ---- Helpers ------------------------------------------------

function cvr(won, total) {
  if (total === 0) return 0;
  return Math.round((won / total) * 1000) / 10;
}

function avgAcv(arr) {
  const won = arr.filter(d => d.isWon && d.amount > 0);
  if (!won.length) return 0;
  return Math.round(won.reduce((s, d) => s + d.amount, 0) / won.length);
}

function totalAcv(arr) {
  return Math.round(arr.filter(d => d.isWon).reduce((s, d) => s + d.amount, 0));
}

function avgCycle(arr) {
  const valid = arr.filter(d => d.isWon && d.salesCycleDays !== null);
  if (!valid.length) return null;
  return Math.round(valid.reduce((s, d) => s + d.salesCycleDays, 0) / valid.length);
}

function groupBy(arr, fn) {
  const map = {};
  for (const d of arr) {
    const k = fn(d) || 'Unknown';
    if (!map[k]) map[k] = [];
    map[k].push(d);
  }
  return map;
}

function buildTable(grouped, minSample) {
  return Object.entries(grouped)
    .filter(([, g]) => g.length >= (minSample || 1))
    .map(([key, g]) => {
      const won = g.filter(d => d.isWon).length;
      return {
        segment:      key,
        won:          won,
        lost:         g.length - won,
        total:        g.length,
        cvr:          cvr(won, g.length),
        avgAcv:       avgAcv(g),
        totalAcv:     totalAcv(g),
        avgCycleDays: avgCycle(g)
      };
    })
    .sort((a, b) => b.total - a.total);
}

function sortedOrder(table, order) {
  return [...table].sort((a, b) => {
    const av = order.indexOf(a.segment); const bv = order.indexOf(b.segment);
    return (av === -1 ? 999 : av) - (bv === -1 ? 999 : bv);
  });
}

// ---- Top-level stats ----------------------------------------

const totalWon   = deals.filter(d => d.isWon).length;
const totalLost  = deals.length - totalWon;
const overallCvr = cvr(totalWon, deals.length);
const wonDeals   = deals.filter(d => d.isWon);
const years      = [...new Set(deals.map(d => d.year).filter(y => y !== 'Unknown'))].sort();

// ---- 1. Year-over-Year Trend --------------------------------

const byYear   = groupBy(deals, d => d.year);
const yoyTable = years.map(yr => {
  const g = byYear[yr] || [];
  const w = g.filter(d => d.isWon).length;
  return { year: yr, won: w, lost: g.length - w, total: g.length, cvr: cvr(w, g.length), avgAcv: avgAcv(g), totalAcv: totalAcv(g) };
});

// ---- 2. Quarterly Trend -------------------------------------

const byYQ         = groupBy(deals, d => d.yearQuarter);
const quarterlyTable = [...new Set(deals.map(d => d.yearQuarter).filter(q => q !== 'Unknown'))]
  .sort()
  .map(yq => {
    const g = byYQ[yq] || [];
    const w = g.filter(d => d.isWon).length;
    return { period: yq, won: w, lost: g.length - w, total: g.length, cvr: cvr(w, g.length) };
  });

// ---- 3. Deal Size Band --------------------------------------

function dealSizeBand(amt) {
  if (!amt || amt <= 0) return 'Unknown';
  if (amt < 5000)       return '<$5K';
  if (amt < 15000)      return '$5K-$15K';
  if (amt < 30000)      return '$15K-$30K';
  if (amt < 60000)      return '$30K-$60K';
  return '$60K+';
}

const dealSizeOrder  = ['<$5K', '$5K-$15K', '$15K-$30K', '$30K-$60K', '$60K+', 'Unknown'];
const dealSizeTable  = sortedOrder(buildTable(groupBy(deals, d => dealSizeBand(d.amount)), 1), dealSizeOrder);

// ---- 4. Revenue Tier ----------------------------------------

const revTierOrder  = ['<$5M', '$5M-$25M', '$25M-$100M', '$100M-$500M', '$500M+', 'Unknown'];
const revTierTable  = sortedOrder(buildTable(groupBy(deals, d => d.revenueTier), 3), revTierOrder);

// ---- 5. Company Size Tier -----------------------------------

const sizeOrder         = ['1-50', '51-200', '201-500', '501-1000', '1001-5000', '5000+', 'Unknown'];
const companySizeTable  = sortedOrder(buildTable(groupBy(deals, d => d.companySizeTier), 3), sizeOrder);

// ---- 6. Industry --------------------------------------------

const industryTable = buildTable(groupBy(deals, d => d.industryTier), 5);

// ---- 7. Company Type ----------------------------------------

const companyTypeTable = buildTable(groupBy(deals, d => d.companyType), 3);

// ---- 8. CRM Platform ----------------------------------------

const crmTable = buildTable(groupBy(deals, d => d.crmPlatform), 3);

// ---- 9. Has RevOps ------------------------------------------

const revopsTable = buildTable(groupBy(deals, d => d.hasRevops), 3);

// ---- 10. Geography ------------------------------------------

const byCountry    = groupBy(deals, d => d.country === 'us' ? 'US' : d.country);
const countryTable = buildTable(byCountry, 3);

const usDeals   = deals.filter(d => d.country === 'US' || d.country === 'us');
const stateTable = buildTable(groupBy(usDeals, d => d.state || 'Unknown'), 3).slice(0, 15);

// ---- 11. Deal Owner (internal + anonymized) -----------------

const dealOwnerTable = buildTable(groupBy(deals, d => d.dealOwner), 2);
const dealOwnerAnon  = dealOwnerTable.map((row, i) => ({ ...row, segment: 'Rep ' + String.fromCharCode(65 + i) }));
const anonMap        = {};
for (let i = 0; i < dealOwnerTable.length; i++) anonMap[dealOwnerTable[i].segment] = dealOwnerAnon[i].segment;

// ---- 12. Sales Cycle (Won deals only) -----------------------

function scBand(days) {
  if (days === null) return 'Unknown';
  if (days <= 7)    return '0-7 days';
  if (days <= 14)   return '8-14 days';
  if (days <= 30)   return '15-30 days';
  if (days <= 60)   return '31-60 days';
  if (days <= 90)   return '61-90 days';
  return '90+ days';
}

const scOrder        = ['0-7 days', '8-14 days', '15-30 days', '31-60 days', '61-90 days', '90+ days', 'Unknown'];
const wonWithCycle   = wonDeals.filter(d => d.salesCycleDays !== null);
const salesCycleTable = sortedOrder(buildTable(groupBy(wonWithCycle, d => scBand(d.salesCycleDays)), 1), scOrder);
const salesCycleByYear = years.map(yr => {
  const g = wonWithCycle.filter(d => d.year === yr);
  return { year: yr, avgDays: avgCycle(g), wonDeals: g.length };
});

// ---- 13. Lost Reasons ---------------------------------------

const lostDeals      = deals.filter(d => !d.isWon);
const lostReasonFreq = Object.entries(groupBy(lostDeals, d => d.lostReason))
  .map(([reason, g]) => ({ reason, count: g.length, pct: cvr(g.length, lostDeals.length) }))
  .sort((a, b) => b.count - a.count);

const topLostIndustries = [...new Set(lostDeals.map(d => d.industryTier))]
  .map(ind => ({ ind, deals: lostDeals.filter(d => d.industryTier === ind) }))
  .sort((a, b) => b.deals.length - a.deals.length)
  .slice(0, 5)
  .map(({ ind, deals: g }) => {
    const top = Object.entries(groupBy(g, d => d.lostReason))
      .map(([r, d]) => ({ reason: r, count: d.length }))
      .sort((a, b) => b.count - a.count).slice(0, 3);
    return { industry: ind, total: g.length, topReasons: top };
  });

// ---- Assemble -----------------------------------------------

return [{ json: {
  metadata: {
    generatedAt:   new Date().toISOString(),
    totalDeals:    deals.length,
    totalWon:      totalWon,
    totalLost:     totalLost,
    overallCvr:    overallCvr,
    overallAvgAcv: avgAcv(deals),
    totalRevenue:  totalAcv(deals),
    yearsInData:   years
  },
  dealSize:       dealSizeTable,
  revenueTier:    revTierTable,
  companySize:    companySizeTable,
  industry:       industryTable,
  companyType:    companyTypeTable,
  crmPlatform:    crmTable,
  hasRevops:      revopsTable,
  geography:      { byCountry: countryTable, byState: stateTable },
  dealOwner:      dealOwnerTable,
  dealOwnerAnon:  dealOwnerAnon,
  anonMap:        anonMap,
  salesCycle: {
    byBand:         salesCycleTable,
    byYear:         salesCycleByYear,
    overallAvgDays: avgCycle(wonWithCycle)
  },
  lostReasons: {
    frequency:      lostReasonFreq,
    byTopIndustry:  topLostIndustries
  },
  trend: {
    yoy:       yoyTable,
    quarterly: quarterlyTable
  }
}}];

// ============================================================
// NODE: Format AI Prompt
// Builds the full structured prompt for the AI Agent.
// Service Line removed — no longer tracked at Full Funnel.
// All numbers come from Pre-Calculate — AI invents nothing.
// ============================================================

const d = $input.first().json;
const m = d.metadata;
const fmt = n => (n || 0).toLocaleString('en-US');

const prompt = `You are a B2B revenue intelligence analyst writing an ICP Closed Won/Lost analysis report for Full Funnel — a B2B GTM and RevOps consulting firm.

Audience: Full Funnel leadership (Matt Iovanni, Steve Barone) — internal strategic use.
Data period: 2023–2026 (${m.yearsInData.join(', ')}).

=== RULES ===
- NEVER calculate or invent numbers. Every stat must come from the data below.
- NEVER hallucinate company names, rep names, industries, or deal details.
- Lead with the insight, then support with data.
- Use markdown tables for all structured comparisons.
- Separate every page with exactly: ===PAGE_BREAK===
- Do NOT use --- as a page separator (conflicts with markdown table syntax).
- Write in a direct, executive-ready tone. No filler.
=== END RULES ===

========== PRE-CALCULATED DATA ==========

OVERALL STATS
Total deals: ${m.totalDeals} | Won: ${m.totalWon} | Lost: ${m.totalLost}
Overall CvR: ${m.overallCvr}%
Avg ACV (Won): $${fmt(m.overallAvgAcv)}
Total Won Revenue: $${fmt(m.totalRevenue)}

YEAR-OVER-YEAR TREND
${JSON.stringify(d.trend.yoy, null, 2)}

QUARTERLY TREND
${JSON.stringify(d.trend.quarterly, null, 2)}

DEAL SIZE BANDS
${JSON.stringify(d.dealSize, null, 2)}

REVENUE TIER
${JSON.stringify(d.revenueTier, null, 2)}

COMPANY SIZE TIER
${JSON.stringify(d.companySize, null, 2)}

INDUSTRY (min 5 deals)
${JSON.stringify(d.industry, null, 2)}

COMPANY TYPE
${JSON.stringify(d.companyType, null, 2)}

CRM PLATFORM
${JSON.stringify(d.crmPlatform, null, 2)}

HAS REVOPS FUNCTION
${JSON.stringify(d.hasRevops, null, 2)}

GEOGRAPHY — BY COUNTRY
${JSON.stringify(d.geography.byCountry, null, 2)}

GEOGRAPHY — US STATES (top 15)
${JSON.stringify(d.geography.byState, null, 2)}

DEAL OWNER — INTERNAL (real rep names)
${JSON.stringify(d.dealOwner, null, 2)}

SALES CYCLE — BY BAND (Won deals only)
${JSON.stringify(d.salesCycle.byBand, null, 2)}

SALES CYCLE — BY YEAR
${JSON.stringify(d.salesCycle.byYear, null, 2)}

SALES CYCLE — OVERALL AVG: ${d.salesCycle.overallAvgDays} days (Won deals)

LOST REASON FREQUENCY
${JSON.stringify(d.lostReasons.frequency, null, 2)}

LOST REASONS BY TOP 5 INDUSTRIES
${JSON.stringify(d.lostReasons.byTopIndustry, null, 2)}

========== END DATA ==========

Write a Gamma-ready report with the pages below. Use ===PAGE_BREAK=== between each page.

PAGE 1 — Executive Summary
Headline stats: total deals, Won/Lost split, CvR, avg ACV, total revenue, data period.
Top 3 ICP findings (insight-first, one sentence each).
Top 3 strategic recommendations.

PAGE 2 — Deal Size & Company Revenue
Deal size band analysis: ACV sweet spot, conversion by band.
Revenue tier: which company revenue range converts best.
Cross-read: do bigger companies pay bigger deals?

PAGE 3 — Industry & Company Profile (Consolidated)
Top converting industries. Company type breakdown. Company size tier.
CRM platform — HubSpot vs Salesforce signal for FF service fit.
RevOps function: does having RevOps correlate with winning?

PAGE 4 — Geography & Latest Year Focus (2025–2026)
US state concentration. International presence.
Zoom in on 2025–2026 deals only: what does the current ICP look like vs historical baseline?

PAGE 5 — Deal Owner Performance (INTERNAL VERSION)
Rep-level table: CvR, avg ACV, total deals, total revenue, avg sales cycle.
Who are the top performers? Any patterns in how top reps win vs others?
Note which reps are former employees (deactivated).

PAGE 6 — Sales Cycle Analysis
Overall avg time-to-close. By deal size band: do bigger deals take longer.
By year: is the sales cycle shortening over time?

PAGE 7 — Win/Loss Reasons
Lost reason frequency table. Top reasons by industry cross-tab.
Ghosted vs Budget vs Competitor: what does this tell us about qualification gaps?

PAGE 8 — CvR Trend & Portfolio Health
Year-over-year CvR improvement. Quarterly trend.
Volume trajectory. Is growth from more deals or better conversion?

PAGE 9 — ICP Summary: Prioritise vs Deprioritise
For each dimension (Industry, Company Size, Revenue Tier, CRM Platform, Company Type, Geography, Deal Size), state: PRIORITISE / NEUTRAL / DEPRIORITISE with a one-sentence rationale based only on the CvR data.

PAGE 10 — Methodology & Data Quality
Data sources (HubSpot export via Clay, LinkedIn enrichment, Claygent tech stack research).
Deal classification logic (NURTURE_EXCLUDE rule, Later Opportunity date threshold).
Known gaps: CRM Platform null for ~50% of records; company names sparse on original Won export (fixed via Clay HubSpot lookup). No Gong data available for this build. Service Line field retired and excluded from analysis.`;

return [{ json: { prompt, anonMap: d.anonMap } }];

// ============================================================
// NODE: Parse AI Response + Anonymize
// 1. Extracts report text from Anthropic response format
// 2. Produces anonymized external version by swapping rep names
// ============================================================

const aiResponse = $input.first().json;
const anonMap    = $node['Format AI Prompt'].json.anonMap || {};

// Extract text — handle both direct string and Anthropic content block format
let reportText = '';
if (typeof aiResponse === 'string') {
  reportText = aiResponse;
} else if (aiResponse.content && Array.isArray(aiResponse.content)) {
  reportText = aiResponse.content.map(b => b.text || '').join('');
} else if (aiResponse.text) {
  reportText = aiResponse.text;
} else {
  reportText = JSON.stringify(aiResponse);
}

// Build anonymized version — replace every real rep name with Rep A/B/C...
let anonReport = reportText;
for (const [realName, anonName] of Object.entries(anonMap)) {
  // Use split/join to replace all occurrences (no regex needed, avoids special char issues)
  anonReport = anonReport.split(realName).join(anonName);
}

const pageCount = (reportText.match(/===PAGE_BREAK===/g) || []).length + 1;

return [{
  json: {
    internalReport: reportText,
    externalReport: anonReport,
    pageCount:      pageCount
  }
}];

